DROP TABLE IF EXISTS `broker_monthly_metrics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `broker_monthly_metrics` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '1',
  `broker_id` int DEFAULT NULL COMMENT 'NULL = admin/global goals row; set for partner-scoped manual actuals',
  `year` int NOT NULL,
  `month` int NOT NULL,
  `lead_to_credit_goal` decimal(5,2) DEFAULT '70.00',
  `credit_to_preapp_goal` decimal(5,2) DEFAULT '50.00',
  `lead_to_closing_goal` decimal(5,2) DEFAULT '25.00',
  `leads_goal` int DEFAULT '40',
  `credit_pulls_goal` int DEFAULT '28',
  `closings_goal` int DEFAULT '10',
  `credit_pulls_actual` int NOT NULL DEFAULT '0',
  `prev_year_leads` int DEFAULT NULL,
  `prev_year_closings` int DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  UNIQUE KEY `uq_tenant_broker_year_month` (`tenant_id`,`broker_id`,`year`,`month`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_broker_id` (`broker_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Monthly broker performance goals (admin, broker_id IS NULL) and per-partner manual actuals';
/*!40101 SET character_set_client = @saved_cs_client */;

