--
-- Table structure for table `communications`
--

DROP TABLE IF EXISTS `communications`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `communications` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '1',
  `application_id` int DEFAULT NULL,
  `lead_id` int DEFAULT NULL,
  `from_user_id` int DEFAULT NULL,
  `from_broker_id` int DEFAULT NULL,
  `to_user_id` int DEFAULT NULL,
  `to_broker_id` int DEFAULT NULL,
  `communication_type` enum('email','sms','whatsapp','call','internal_note') COLLATE utf8mb4_unicode_ci NOT NULL,
  `direction` enum('inbound','outbound') COLLATE utf8mb4_unicode_ci NOT NULL,
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `body` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `media_url` text COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'URL(s) of MMS media attachments — JSON array for multiple items, plain URL for single',
  `media_content_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'MIME type of the primary media attachment (e.g. image/jpeg, application/pdf)',
  `status` enum('pending','sent','delivered','failed','read') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `external_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `recording_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Twilio recording URL (mp3) for call communications',
  `recording_duration` int DEFAULT NULL COMMENT 'Recording duration in seconds',
  `conversation_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mailbox_id` int DEFAULT NULL,
  `source_execution_id` int DEFAULT NULL COMMENT 'reminder_flow_executions.id that produced this message (NULL = manual send)',
  `thread_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reply_to_id` int DEFAULT NULL,
  `message_type` enum('text','image','document','audio','video','template') COLLATE utf8mb4_unicode_ci DEFAULT 'text',
  `template_id` int DEFAULT NULL,
  `delivery_status` enum('pending','sent','delivered','read','failed','rejected') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `delivery_timestamp` datetime DEFAULT NULL,
  `read_timestamp` datetime DEFAULT NULL,
  `error_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `error_message` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cost` decimal(10,4) DEFAULT NULL COMMENT 'Cost in USD for SMS/WhatsApp messages',
  `provider_response` json DEFAULT NULL COMMENT 'Full provider response for debugging',
  `metadata` json DEFAULT NULL,
  `scheduled_at` datetime DEFAULT NULL,
  `sent_at` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `from_user_id` (`from_user_id`),
  KEY `from_broker_id` (`from_broker_id`),
  KEY `to_user_id` (`to_user_id`),
  KEY `to_broker_id` (`to_broker_id`),
  KEY `idx_application_id` (`application_id`),
  KEY `idx_lead_id` (`lead_id`),
  KEY `idx_communication_type` (`communication_type`),
  KEY `idx_created_at` (`created_at`),
  KEY `tenant_id` (`tenant_id`),
  KEY `idx_conversation_id` (`conversation_id`),
  KEY `idx_thread_id` (`thread_id`),
  KEY `idx_reply_to_id` (`reply_to_id`),
  KEY `idx_message_type` (`message_type`),
  KEY `idx_delivery_status` (`delivery_status`),
  KEY `idx_delivery_timestamp` (`delivery_timestamp`),
  KEY `idx_communications_conversation` (`conversation_id`,`tenant_id`),
  KEY `idx_communications_type` (`communication_type`,`tenant_id`),
  KEY `idx_communications_status` (`status`,`delivery_status`),
  KEY `idx_communications_created` (`created_at`),
  KEY `idx_comm_source_exec` (`source_execution_id`),
  KEY `idx_communications_recording` (`recording_url`(100)),
  KEY `idx_communications_mailbox_id` (`mailbox_id`),
  CONSTRAINT `communications_ibfk_1` FOREIGN KEY (`application_id`) REFERENCES `loan_applications` (`id`) ON DELETE SET NULL,
  CONSTRAINT `communications_ibfk_2` FOREIGN KEY (`lead_id`) REFERENCES `leads` (`id`) ON DELETE SET NULL,
  CONSTRAINT `communications_ibfk_3` FOREIGN KEY (`from_user_id`) REFERENCES `clients` (`id`) ON DELETE SET NULL,
  CONSTRAINT `communications_ibfk_4` FOREIGN KEY (`from_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `communications_ibfk_5` FOREIGN KEY (`to_user_id`) REFERENCES `clients` (`id`) ON DELETE SET NULL,
  CONSTRAINT `communications_ibfk_6` FOREIGN KEY (`to_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_communications_reply_to` FOREIGN KEY (`reply_to_id`) REFERENCES `communications` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_communications_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_communications_mailbox_id` FOREIGN KEY (`mailbox_id`) REFERENCES `conversation_email_mailboxes` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci AUTO_INCREMENT=3720005;
/*!40101 SET character_set_client = @saved_cs_client */;

