INSERT INTO `communications` VALUES (4,1,NULL,NULL,NULL,NULL,NULL,NULL,'sms','outbound',NULL,'Hi Lionel! 🏠 Great news — we received your home purchase application (#LA11598165) and our team is already reviewing it. Questions? Just reply! – {{broker_name}}, Encore Mortgage. Reply STOP to opt out.',NULL,NULL,'sent','SMe37137390f0127de7017d163b87a9304',NULL,NULL,'conv_client_32_loan_37_flow_3',7,NULL,NULL,'text',23,'sent',NULL,NULL,NULL,NULL,0.0000,NULL,NULL,NULL,'2026-03-24 22:10:02','2026-03-24 22:10:02'),(5,1,NULL,NULL,NULL,NULL,NULL,NULL,'email','outbound','🏠 We\'ve Received Your Purchase Loan Application!','Hi Lionel,\n\nExciting news! Your home purchase loan application has been officially received and is now in our system.\n\nApplication #: LA11598165\n\nOur team will begin a thorough review right away. Here\'s what to expect:\n\n• We\'ll contact you within 1 business day with next steps.\n• You may be asked to provide supporting documents through your client portal.\n• We\'ll keep you updated every step of the way.\n\nWe\'re thrilled to be part of your homeownership journey. Don\'t hesitate to reach out with any questions!\n\n{{broker_name}}\nEncore Mortgage',NULL,NULL,'sent','<enc-conv_client_32_loan_37_flow_3-1774411802650@disruptinglabs.com>',NULL,NULL,'conv_client_32_loan_37_flow_3',7,NULL,NULL,'text',24,'sent',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-03-24 22:10:03','2026-03-24 22:10:03'),(6,1,NULL,NULL,NULL,NULL,NULL,1,'sms','inbound',NULL,'Thanks for sharing that update. If you have any questions about your credit or need info on next steps, just let me know how I can help.',NULL,NULL,'delivered','SM1488b08f8dd63d0fa747ce2c55cfbcf7',NULL,NULL,'conv_client_32_loan_37_flow_3',NULL,NULL,NULL,'text',NULL,'delivered',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-03-24 22:10:16','2026-03-24 22:10:16'),(7,1,NULL,NULL,NULL,NULL,NULL,NULL,'email','outbound','What Happens Next with Your Purchase Loan (#LA11598165)','Hi Lionel,\n\nJust following up! Now that w