  `approved_amount` decimal(12,2) NOT NULL COMMENT 'Current pre-approved amount shown on letter (can be edited up to max_approved_amount)',
  `max_approved_amount` decimal(12,2) NOT NULL COMMENT 'Maximum pre-approval ceiling — set only by admin brokers, cannot be exceeded',
  `html_content` longtext COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Fully customizable HTML body of the letter',
  `letter_date` date NOT NULL COMMENT 'Date shown on the letter',
  `expires_at` date DEFAULT NULL COMMENT 'Optional expiration date for the pre-approval',
  `loan_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Loan type shown on the letter: FHA, Conventional, USDA, VA, Non-QM',
  `fico_score` smallint DEFAULT NULL COMMENT 'FICO credit score shown on the letter',
  `purchase_property_address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Street address of the property the client intends to purchase',
  `purchase_property_city` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'City of the intended purchase property',
  `purchase_property_state` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'State of the intended purchase property',
  `purchase_property_zip` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ZIP code of the intended purchase property',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 = active/enabled, 0 = disabled',
  `created_by_broker_id` int NOT NULL COMMENT 'Broker who issued the letter',
  `updated_by_broker_id` int DEFAULT NULL COMMENT 'Broker who last edited the letter',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
