  KEY `idx_pre_approval_application` (`application_id`),
  KEY `idx_pre_approval_created_by` (`created_by_broker_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci AUTO_INCREMENT=60006 COMMENT='Pre-approval letters attached to loan applications. One letter per loan, customizable HTML content.';
