--
-- Table structure for table `reminder_flows`
--

DROP TABLE IF EXISTS `reminder_flows`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reminder_flows` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '1',
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `trigger_event` enum('app_sent','application_received','prequalified','preapproved','under_contract_loan_setup','submitted_to_underwriting','approved_with_conditions','clear_to_close','docs_out','loan_funded','task_pending','task_in_progress','task_overdue','no_activity','manual','prospect_contact_attempted','prospect_contacted','prospect_appt_set','prospect_waiting_for_1st_deal','prospect_first_deal_funded','prospect_second_deal_funded','prospect_top_agent_whale') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'app_sent',
  `trigger_delay_days` int NOT NULL DEFAULT '0' COMMENT 'Days after trigger event to start flow',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `apply_to_all_loans` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'When true, applies to all current and future loans',
  `loan_type_filter` enum('all','purchase','refinance') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'all' COMMENT 'Restrict this flow to a specific loan type or all',
  `flow_category` enum('loan','realtor_prospecting') NOT NULL DEFAULT 'loan',
  `created_by_broker_id` int DEFAULT NULL,
  `restricted_to_broker_id` int DEFAULT NULL COMMENT 'NULL = visible to all brokers in tenant. Otherwise only this broker can see/run the flow.',
  `enable_trace_logging` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'When 1, engine writes per-step rows into reminder_flow_step_logs.',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_reminder_flows_tenant` (`tenant_id`),
  KEY `idx_reminder_flows_active` (`is_active`),
  KEY `fk_reminder_flows_broker` (`created_by_broker_id`),
  KEY `idx_reminder_flows_trigger_loantype` (`trigger_event`,`loan_type_filter`,`is_active`),
  KEY `idx_reminder_flows_category` (`flow_category`,`is_active`),
  KEY `idx_reminder_flows_restricted_broker` (`restricted_to_broker_id`),
  CONSTRAINT `fk_reminder_flows_restricted_broker` FOREIGN KEY (`restricted_to_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci AUTO_INCREMENT=30004;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `reminder_flows`
--

/*!40000 ALTER TABLE `reminder_flows` DISABLE KEYS */;
INSERT INTO `reminder_flows` VALUES (3,1,'Application Received — Nurture Sequence','Triggered when a loan application status moves to application_received. Checks the application is not in an adverse state, then branches by loan type (Purchase / Refi). Default (unclassified) follows the Purchase sequence. Cadence: SMS → Email → 10-min wait → Email → 2-day wait → SMS.','application_received',0,1,1,'all',1,'2026-03-12 22:05:46','2026-03-12 22:05:46'),(5,1,'Preapproved — Nurture Drip Sequence','Triggered when loan status becomes preapproved. Branches by loan type (Purchase/Refi/Default→Purchase). Pure time-based drip — no response gates. 12 SMS + 11 Email over ~88 days. Both branches start with immediate SMS+Email, then share an escalating sequence.','preapproved',0,1,1,'all',1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(6,1,'Under Contract/Loan Set Up — Welcome Sequence','Triggered immediately when loan status becomes under_contract_loan_setup. Sends an SMS followed by an Email with details on next steps. No branching.','under_contract_loan_setup',0,1,1,'all',1,'2026-03-12 22:50:22','2026-03-12 22:50:22'),(7,1,'Submitted to Underwriting — Notification Sequence','Triggered immediately when loan status becomes submitted_to_underwriting. Sends an SMS and an Email explaining the underwriting process and what the client should expect. No branching.','submitted_to_underwriting',0,1,1,'all',1,'2026-03-12 22:51:53','2026-03-12 22:51:53'),(8,1,'Approved with Conditions — Notification Sequence','Triggered immediately when loan status becomes approved_with_conditions. Sends client an SMS + Email explaining the conditional approval. Then fires three internal notifications to alert the team to contact the Buyer Agent, Listing Agent, and Title Agent respectively.','approved_with_conditions',0,1,1,'all',1,'2026-03-12 22:55:03','2026-03-12 22:55:03'),(9,1,'Clear to Close — Closing Notification Sequence','Triggered immediately when loan status becomes clear_to_close. Sends a shared SMS, then branches by loan type: Purchase gets a purchase-specific closing prep email, Refi gets a refi-specific closing prep email. Default (Nada) routes to the Purchase email.','clear_to_close',0,1,1,'all',1,'2026-03-12 22:57:51','2026-03-12 22:57:51'),(10,1,'Loan Funded — Closing Day Congratulations','Triggered when loan status becomes loan_funded. Checks if actual_close_date is set. If yes, waits until the close date then sends a congratulatory SMS + Email. If no close date is set (Nada), the flow ends without sending.','loan_funded',0,1,1,'all',1,'2026-03-12 23:02:15','2026-03-12 23:02:43');
/*!40000 ALTER TABLE `reminder_flows` ENABLE KEYS */;

