INSERT INTO `task_form_fields` VALUES (35,34,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a clear photo or scan of your valid government-issued ID (passport, driver license, state ID, etc.).','2026-02-26 18:03:40'),(36,35,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a clear photo or scan of your valid driver\'s license (front and back).','2026-02-26 18:03:40'),(37,36,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a clear photo or scan of your valid Green Card (front and back).','2026-02-26 18:03:40'),(38,37,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a clear photo or scan of your Social Security card. Make sure the number is clearly visible.','2026-02-26 18:03:40'),(39,38,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the last two months of bank or mortgage statements. They must clearly show the account holder name, partial account number, and housing payment transactions.','2026-02-26 18:03:40'),(40,39,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the active homeowner\'s insurance policy. It must include the policy number, coverage details, insured name, and effective dates.','2026-02-26 18:03:40'),(41,40,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach all W-2 forms from the most recent tax year. If you have multiple employers, include the W-2 from each one.','2026-02-26 18:03:40'),(42,41,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach all 1099 forms (1099-MISC, 1099-NEC, 1099-INT, etc.) for the last two tax years. Include all issuers.','2026-02-26 18:03:40'),(43,42,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach complete and signed IRS Form 1040 with all schedules (Schedule C, E, etc.) for the last two tax years.','2026-02-26 18:03:40'),(44,43,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a copy of your valid business license, DBA registration, or LLC/corporation certificate.','2026-02-26 18:03:40'),(45,44,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a YTD profit & loss statement prepared by a CPA or bookkeeper. Must include revenue, expenses, and net income.','2026-02-26 18:03:40'),(46,45,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the last 3 months of all business bank statements. Must show account holder name, account number (partial), and all transactions.','2026-02-26 18:03:40'),(47,46,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the last 2 months of all investment, brokerage, or retirement account statements (401k, IRA, etc.).','2026-02-26 18:03:40'),(48,47,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the most recent pension or retirement award/benefit letter. It must show the monthly payment amount and the issuing organization.','2026-02-26 18:03:40'),(49,48,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your most recent Social Security award letter showing your monthly benefit amount. You can obtain it from ssa.gov.','2026-02-26 18:03:40'),(50,49,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach a clear copy of your valid visa, I-94 Arrival/Departure Record, Employment Authorization Document (EAD), or other immigration status document.','2026-02-26 18:03:40'),(51,50,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your IRS ITIN assignment letter (Notice CP565) showing your Individual Taxpayer Identification Number.','2026-02-26 18:03:40'),(52,51,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your most recent mortgage statement showing the current balance, monthly payment, and lender information.','2026-02-26 18:03:40'),(53,52,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the most recent property tax assessment or bill from your county/city assessor.','2026-02-26 18:03:40'),(54,53,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the signed purchase agreement (sales contract) including all addenda and counteroffers.','2026-02-26 18:03:40'),(55,54,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the architectural/engineering plans for the construction project and the signed builder contract including total cost breakdown.','2026-02-26 18:03:40'),(56,55,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the current HOA dues statement and the master/blanket insurance policy (hazard + liability) for the condo association.','2026-02-26 18:03:40'),(57,56,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach all signed lease agreements currently in effect for each rental unit in the property. Include lease start/end dates and monthly rent amounts.','2026-02-26 18:03:40'),(58,57,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the last 2 years of income statements and balance sheets for the business operating at or owning the commercial property. CPA-prepared preferred.','2026-02-26 18:03:40'),(66,58,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the last two months of all bank account statements. Must show account holder name, partial account number, and all transactions.','2026-03-04 20:24:14'),(67,59,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your most recent consecutive pay stubs covering at least one month. Must show employer name, gross pay, deductions, and year-to-date totals.','2026-03-04 20:24:14'),(68,60,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your complete and signed federal tax returns (Form 1040) or Schedule C for the last two tax years. Include all schedules and attachments.','2026-03-04 20:24:14'),(69,61,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your most recent mortgage statement showing outstanding balance, monthly payment, lender name, and property address.','2026-03-04 20:24:14'),(70,62,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach the current insurance policy (declaration page). Must include policy number, coverage amounts, property address, named insured, and effective dates.','2026-03-04 20:24:14'),(71,63,'document_upload','Attach Document','file_pdf',NULL,1,NULL,NULL,0,'Attach your most recent mortgage statement or an official payoff letter from your lender. Must show current balance, monthly payment, and lender contact information.','2026-03-04 20:24:14');
