INSERT INTO `task_templates` VALUES (34,1,'Government-Issued ID','Provide a valid government-issued photo identification.','document_verification','high',7,10,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach a clear photo or scan of your valid government-issued ID (passport, driver license, state ID, etc.).',0,0),(35,1,'Driver\'s License','Provide your valid driver\'s license as a form of identification.','document_verification','high',7,11,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach a clear photo or scan of your valid driver\'s license (front and back).',0,0),(36,1,'Green Card (Permanent Resident Card)','Provide your valid Permanent Resident Card (Form I-551).','document_verification','high',7,12,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach a clear photo or scan of your valid Green Card (front and back).',0,0),(37,1,'Social Security Card (SSN)','Provide your Social Security card issued by the Social Security Administration (SSA).','document_verification','high',7,13,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach a clear photo or scan of your Social Security card. Make sure the number is clearly visible.',0,0),(38,1,'Housing Payment Statement (2 Months)','Provide the last two months of bank or mortgage statements showing your housing payment.','document_verification','medium',14,14,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach the last two months of bank or mortgage statements. They must clearly show the account holder name, partial account number, and housing payment transactions.',0,0),(39,1,'Homeowner\'s Insurance Policy','Provide the current homeowner\'s insurance policy for the property.','document_verification','medium',14,15,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach the active homeowner\'s insurance policy. It must include the policy number, coverage details, insured name, and effective dates.',0,0),(40,1,'W-2 Form','Provide your W-2 form(s) for the most recent tax year.','document_verification','high',14,16,1,1,'2026-02-25 20:23:05','2026-02-25 20:23:05',1,'Attach all W-2 forms from the most recent tax year. If you have multiple employers, include the W-2 from each one.',0,0),(41,1,'1099 Forms (Last 2 Years)','Provide all 1099 forms received in the last two tax years.','document_verification','high',14,20,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach all 1099 forms (1099-MISC, 1099-NEC, 1099-INT, etc.) for the last two tax years. Include all issuers.',0,0),(42,1,'Federal Tax Returns Last 2 Years Including Business Tax Returns','Provide signed federal tax returns (Form 1040) for the last two years, including all business tax returns (Schedule C, 1120-S, 1065, etc.) and all schedules.','document_verification','high',14,21,1,1,'2026-02-25 21:40:00','2026-03-04 20:24:13',1,'Attach complete and signed IRS Form 1040 with all business tax returns (Schedule C, 1120-S, 1065, etc.) for the last two tax years.',0,0),(43,1,'Business License','Provide a copy of your current business license or registration.','document_verification','medium',10,22,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach a copy of your valid business license, DBA registration, or LLC/corporation certificate.',0,0),(44,1,'Profit & Loss Statement (Current Year)','Provide a year-to-date profit & loss statement for your business.','document_verification','high',10,23,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach a YTD profit & loss statement prepared by a CPA or bookkeeper. Must include revenue, expenses, and net income.',0,0),(45,1,'Business Bank Statements (3 Months)','Provide the last 3 months of business bank statements.','document_verification','high',14,24,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the last 3 months of all business bank statements. Must show account holder name, account number (partial), and all transactions.',0,0),(46,1,'Investment / Brokerage Account Statements (2 Months)','Provide the last 2 months of investment or brokerage account statements.','document_verification','medium',14,25,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the last 2 months of all investment, brokerage, or retirement account statements (401k, IRA, etc.).',0,0),(47,1,'Pension / Retirement Award Letter','Provide a pension or retirement benefit award letter showing monthly income.','document_verification','medium',14,26,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the most recent pension or retirement award/benefit letter. It must show the monthly payment amount and the issuing organization.',0,0),(48,1,'Social Security Award Letter','Provide the most recent Social Security benefits award letter.','document_verification','medium',14,27,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach your most recent Social Security award letter showing your monthly benefit amount. You can obtain it from ssa.gov.',0,0),(49,1,'Visa / Work Authorization Document','Provide a copy of your current visa or work authorization document (I-94, EAD, H-1B, etc.).','document_verification','high',7,28,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach a clear copy of your valid visa, I-94 Arrival/Departure Record, Employment Authorization Document (EAD), or other immigration status document.',0,0),(50,1,'ITIN Assignment Letter','Provide the IRS ITIN assignment letter (CP565 notice).','document_verification','medium',7,29,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach your IRS ITIN assignment letter (Notice CP565) showing your Individual Taxpayer Identification Number.',0,0),(51,1,'Current Mortgage Statement','Provide the most recent monthly mortgage statement for the property being refinanced.','document_verification','high',7,30,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach your most recent mortgage statement showing the current balance, monthly payment, and lender information.',0,0),(52,1,'Most Recent Property Tax Bill','Provide the most recent property tax bill for the subject property.','document_verification','medium',14,31,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the most recent property tax assessment or bill from your county/city assessor.',0,0),(53,1,'Purchase Agreement / Offer Letter','Provide a fully executed purchase agreement or offer letter for the property.','document_verification','high',5,32,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the signed purchase agreement (sales contract) including all addenda and counteroffers.',0,0),(54,1,'Construction Plans & Builder Contract','Provide the construction plans and a signed contract with your builder.','document_verification','high',10,33,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the architectural/engineering plans for the construction project and the signed builder contract including total cost breakdown.',0,0),(55,1,'HOA Statement & Master Insurance Policy','Provide the current HOA statement and the master insurance policy for the condo community.','document_verification','medium',14,34,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the current HOA dues statement and the master/blanket insurance policy (hazard + liability) for the condo association.',0,0),(56,1,'Existing Lease Agreements','Provide copies of all current lease agreements for the rental units.','document_verification','medium',14,35,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach all signed lease agreements currently in effect for each rental unit in the property. Include lease start/end dates and monthly rent amounts.',0,0),(57,1,'Business Financial Statements','Provide the last 2 years of business financial statements (income statement & balance sheet).','document_verification','high',14,36,1,1,'2026-02-25 21:40:00','2026-02-25 21:40:00',1,'Attach the last 2 years of income statements and balance sheets for the business operating at or owning the commercial property. CPA-prepared preferred.',0,0),(58,1,'2 Months Bank Statements','Provide your last two months of bank statements for all accounts.','document_verification','medium',14,14,1,1,'2026-03-04 20:24:13','2026-03-04 20:24:13',1,'Attach the last two months of all bank account statements. Must show account holder name, partial account number, and all transactions.',0,0),(59,1,'Most Recent Pay-Stubs (1 Month)','Provide your most recent one month of consecutive pay stubs from your employer.','document_verification','high',10,17,1,1,'2026-03-04 20:24:13','2026-03-04 20:24:13',1,'Attach your most recent consecutive pay stubs covering at least one month. Must show employer name, gross pay, deductions, and year-to-date totals.',0,0),(60,1,'Federal Tax Returns (Last 2 Years) or Schedule C (Last 2 Years)','Provide your federal income tax returns or Schedule C for the last two tax years.','document_verification','high',14,22,1,1,'2026-03-04 20:24:13','2026-03-04 20:24:13',1,'Attach your complete and signed federal tax returns (Form 1040) or Schedule C for the last two tax years. Include all schedules and attachments.',0,0),(61,1,'Mortgage Statement','Provide the most recent mortgage statement for the subject property.','document_verification','medium',10,31,1,1,'2026-03-04 20:24:13','2026-03-04 20:24:13',1,'Attach your most recent mortgage statement showing outstanding balance, monthly payment, lender name, and property address.',0,0),(62,1,'Insurance Policy','Provide the current homeowners or property insurance policy for the subject property.','document_verification','medium',14,32,1,1,'2026-03-04 20:24:13','2026-03-04 20:24:13',1,'Attach the current insurance policy (declaration page). Must include policy number, coverage amounts, property address, named insured, and effective dates.',0,0),(63,1,'Current Mortgage Statement / Payoff Letter','Provide the most recent mortgage statement or an official payoff letter for the property being refinanced.','document_verification','high',7,33,1,1,'2026-03-04 20:24:13','2026-03-04 20:24:13',1,'Attach your most recent mortgage statement or an official payoff letter from your lender. Must show current balance, monthly payment, and lender contact information.',0,0);
