DROP TABLE IF EXISTS `tasks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tasks` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '1',
  `template_id` int DEFAULT NULL COMMENT 'References task_template if created from template',
  `order_index` int DEFAULT '0' COMMENT 'Order in loan workflow (copied from template)',
  `application_id` int DEFAULT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `task_type` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Matches task_template.task_type',
  `status` enum('pending','in_progress','completed','pending_approval','approved','reopened','cancelled','overdue') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `priority` enum('low','medium','high','urgent') COLLATE utf8mb4_unicode_ci DEFAULT 'medium',
  `assigned_to_user_id` int DEFAULT NULL,
  `assigned_to_broker_id` int DEFAULT NULL,
  `created_by_broker_id` int DEFAULT NULL,
  `due_date` datetime DEFAULT NULL,
  `completed_at` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `form_completed` tinyint(1) DEFAULT '0' COMMENT 'Whether custom form is completed',
  `form_completed_at` datetime DEFAULT NULL COMMENT 'When form was completed',
  `documents_uploaded` tinyint(1) DEFAULT '0' COMMENT 'Whether required documents are uploaded',
  `documents_verified` tinyint(1) DEFAULT '0' COMMENT 'Whether uploaded documents are verified by broker',
  `approval_status` enum('pending','approved','rejected') COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Approval status by broker/admin',
  `approved_by_broker_id` int DEFAULT NULL COMMENT 'Broker who approved the task',
  `approved_at` datetime DEFAULT NULL COMMENT 'When task was approved',
  `reopened_by_broker_id` int DEFAULT NULL COMMENT 'Broker who reopened the task',
  `reopened_at` datetime DEFAULT NULL COMMENT 'When task was reopened',
  `reopen_reason` text COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Reason for reopening task',
  `status_change_reason` text COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Reason/comment for manual status changes',
  `status_changed_by_broker_id` int DEFAULT NULL COMMENT 'Broker who manually changed status',
  `status_changed_at` datetime DEFAULT NULL COMMENT 'When status was manually changed',
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `created_by_broker_id` (`created_by_broker_id`),
  KEY `idx_application_id` (`application_id`),
  KEY `idx_assigned_to_user` (`assigned_to_user_id`),
  KEY `idx_assigned_to_broker` (`assigned_to_broker_id`),
  KEY `idx_status` (`status`),
  KEY `idx_due_date` (`due_date`),
  KEY `idx_template` (`template_id`),
  KEY `idx_application_status` (`application_id`,`status`),
  KEY `idx_tasks_form_completed` (`form_completed`),
  KEY `idx_tasks_documents_uploaded` (`documents_uploaded`),
  KEY `fk_tasks_approved_by` (`approved_by_broker_id`),
  KEY `fk_tasks_reopened_by` (`reopened_by_broker_id`),
  KEY `tenant_id` (`tenant_id`),
  KEY `fk_tasks_status_changed_by_broker` (`status_changed_by_broker_id`),
  KEY `idx_tasks_status_changes` (`status_changed_at`,`status_changed_by_broker_id`),
  KEY `idx_tasks_audit_tracking` (`status`,`status_changed_at`,`application_id`),
  CONSTRAINT `fk_task_template` FOREIGN KEY (`template_id`) REFERENCES `task_templates` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_tasks_approved_by` FOREIGN KEY (`approved_by_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_tasks_reopened_by` FOREIGN KEY (`reopened_by_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_tasks_status_changed_by_broker` FOREIGN KEY (`status_changed_by_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_tasks_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `tasks_ibfk_1` FOREIGN KEY (`application_id`) REFERENCES `loan_applications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `tasks_ibfk_3` FOREIGN KEY (`assigned_to_user_id`) REFERENCES `clients` (`id`) ON DELETE SET NULL,
  CONSTRAINT `tasks_ibfk_4` FOREIGN KEY (`assigned_to_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL,
  CONSTRAINT `tasks_ibfk_5` FOREIGN KEY (`created_by_broker_id`) REFERENCES `brokers` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci AUTO_INCREMENT=270024;
/*!40101 SET character_set_client = @saved_cs_client */;

