--
-- Table structure for table `templates`
--

DROP TABLE IF EXISTS `templates`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '1',
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `template_type` enum('email','sms','whatsapp') COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` enum('welcome','reminder','update','follow_up','marketing','system') COLLATE utf8mb4_unicode_ci DEFAULT 'system',
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'For email templates',
  `body` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `variables` json DEFAULT NULL COMMENT 'Available template variables',
  `is_active` tinyint(1) DEFAULT '1',
  `usage_count` int DEFAULT '0',
  `created_by_broker_id` int NOT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_tenant_type` (`tenant_id`,`template_type`),
  KEY `idx_category` (`category`),
  KEY `idx_active` (`is_active`),
  KEY `idx_created_by` (`created_by_broker_id`),
  KEY `idx_templates_type` (`template_type`,`tenant_id`),
  KEY `idx_templates_active` (`is_active`,`tenant_id`),
  KEY `idx_templates_category` (`category`,`tenant_id`),
  CONSTRAINT `fk_templates_broker` FOREIGN KEY (`created_by_broker_id`) REFERENCES `brokers` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_templates_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci AUTO_INCREMENT=30002;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `templates`
--

/*!40000 ALTER TABLE `templates` DISABLE KEYS */;
INSERT INTO `templates` VALUES (1,1,'Welcome Email','Welcome new clients to the loan process','email','welcome','Welcome to Encore Mortgage - Your Loan Application','Dear {{client_name}},\n\nWelcome to Encore Mortgage! We\'re excited to help you with your loan application.\n\nYour application ID is: {{application_id}}\n\nNext steps:\n1. Complete all required documents\n2. Schedule your initial consultation\n3. We\'ll review your application within 24-48 hours\n\nIf you have any questions, please don\'t hesitate to contact us.\n\nBest regards,\n{{broker_name}}\nEncore Mortgage','[\"client_name\", \"application_id\", \"broker_name\"]',1,0,1,'2026-02-04 15:11:33','2026-02-04 15:11:33'),(2,1,'Document Reminder SMS','Remind clients about pending documents','sms','reminder',NULL,'Hi {{client_name}}, this is {{broker_name}} from Encore Mortgage. You have {{document_count}} pending documents for your loan application. Please upload them at your earliest convenience.','[\"client_name\", \"broker_name\", \"document_count\"]',1,0,1,'2026-02-04 15:11:33','2026-03-24 22:36:04'),(3,1,'Application Update WhatsApp','Update clients on application status via WhatsApp','whatsapp','update',NULL,'Hi {{client_name}} 👋\n\nGreat news! Your loan application status has been updated to: *{{status}}*\n\n{{additional_notes}}\n\nNext steps: {{next_steps}}\n\nFeel free to reply with any questions!\n\n- {{broker_name}} at Encore Mortgage','[\"client_name\", \"status\", \"additional_notes\", \"next_steps\", \"broker_name\"]',1,0,1,'2026-02-04 15:11:33','2026-02-04 15:11:33'),(4,1,'Loan Approved Email','Congratulate clients on loan approval','email','update','Congratulations! Your Loan Has Been Approved','Dear {{client_name}},\n\nCongratulations! 🎉\n\nWe\'re thrilled to inform you that your loan application #{{application_id}} has been APPROVED!\n\nLoan Details:\n- Loan Amount: ${{loan_amount}}\n- Interest Rate: {{interest_rate}}%\n- Closing Date: {{closing_date}}\n\nNext Steps:\n1. Review the loan documents we\'ll send shortly\n2. Schedule your closing appointment\n3. Prepare for your new home!\n\nThank you for choosing Encore Mortgage. We\'re excited to be part of your homeownership journey!\n\nBest regards,\n{{broker_name}}\nEncore Mortgage','[\"client_name\", \"application_id\", \"loan_amount\", \"interest_rate\", \"closing_date\", \"broker_name\"]',1,0,1,'2026-02-04 15:11:33','2026-02-04 15:11:33'),(5,1,'Quick Update SMS','Send quick status updates via SMS','sms','update',NULL,'Hi {{client_name}}! Quick update on your loan app #{{application_id}}: {{status_message}}. Questions? Call us! - {{broker_name}} at Encore Mortgage','[\"client_name\", \"application_id\", \"status_message\", \"broker_name\"]',1,0,1,'2026-02-04 15:11:33','2026-02-04 15:11:33'),(6,1,'Document Upload Reminder WhatsApp','Friendly WhatsApp reminder for documents','whatsapp','reminder',NULL,'Hi {{client_name}} 👋\n\nFriendly reminder: We\'re still waiting for {{missing_documents}} for your loan application.\n\nYou can upload them easily through your client portal: {{portal_link}}\n\nNeed help? Just reply here and I\'ll assist you right away!\n\n📋 Missing: {{missing_documents}}\n⏰ Needed by: {{due_date}}\n\nThanks!\n{{broker_name}} 🏠','[\"client_name\", \"missing_documents\", \"portal_link\", \"due_date\", \"broker_name\"]',1,0,1,'2026-02-04 15:11:33','2026-02-04 15:11:33'),(7,1,'App Sent – Purchase Welcome Email','First email sent when a purchase loan application is received','email','follow_up','🏠 Your Home Purchase Loan Application Has Been Received!','Hi {{first_name}},\n\nWe\'re excited to let you know that your home *purchase* loan application has been received and is now under review.\n\nApplication #: {{application_number}}\n\nHere\'s what happens next:\n1. Our team will review your information within 1 business day.\n2. We\'ll reach out if we need any additional documents.\n3. You\'ll receive updates at every step of the process.\n\nIf you have any questions or need assistance, reply to this email or call us anytime.\n\nLooking forward to helping you get those keys! 🔑\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(8,1,'App Sent – Purchase Confirmation SMS','Quick SMS confirmation after purchase application is received','sms','follow_up',NULL,'Hi {{first_name}}! ✅ We received your home purchase application (#{{application_number}}). Our team is already on it! Questions? Just reply. – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(9,1,'App Sent – Purchase Follow-Up Email','Follow-up email for purchase loan, same day','email','follow_up','Next Steps for Your Home Purchase Loan','Hi {{first_name}},\n\nJust following up on your home purchase loan application (#{{application_number}}).\n\nTo keep things moving smoothly, please make sure the following are ready:\n• Government-issued photo ID\n• Last 2 months of pay stubs\n• Last 2 years of W-2s or tax returns\n• Last 2 months of bank statements\n\nYou can upload documents directly through your client portal. If you haven\'t logged in yet, check the link in your welcome email.\n\nWe\'re with you every step of the way. Don\'t hesitate to reach out!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(10,1,'App Sent – Purchase Day-3 Reminder SMS','SMS reminder 3 days after purchase application received','sms','reminder',NULL,'Hi {{first_name}}, it\'s {{broker_name}} from Encore Mortgage. Checking in on your purchase loan app (#{{application_number}}). Have you had a chance to upload your documents? We\'re here to help – just reply!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(11,1,'App Sent – Purchase Day-6 Final SMS','Final SMS nudge 6 days after purchase application received','sms','reminder',NULL,'Hi {{first_name}}! 👋 Still here to help with your home purchase loan (#{{application_number}}). A quick call could get you one step closer to those keys! Call or reply anytime. – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(12,1,'App Sent – Refi Welcome Email','First email sent when a refinance loan application is received','email','follow_up','🔄 Your Refinance Application Has Been Received!','Hi {{first_name}},\n\nGreat news — your refinance loan application has been received and is now under review.\n\nApplication #: {{application_number}}\n\nRefinancing can save you money, lower your payment, or help you access equity. We\'re here to make the process as smooth as possible.\n\nWhat to expect next:\n1. We\'ll review your application within 1 business day.\n2. We may reach out for additional documents.\n3. We\'ll keep you updated every step of the way.\n\nQuestions? Just reply to this email!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(13,1,'App Sent – Refi Confirmation SMS','Quick SMS confirmation after refinance application is received','sms','follow_up',NULL,'Hi {{first_name}}! ✅ We received your refinance application (#{{application_number}}). We\'re reviewing it now! Questions? Just reply. – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(14,1,'App Sent – Refi Follow-Up Email','Follow-up email for refi loan, same day','email','follow_up','Next Steps for Your Refinance','Hi {{first_name}},\n\nFollowing up on your refinance application (#{{application_number}}).\n\nTo keep things moving, please have these documents ready:\n• Government-issued photo ID\n• Last 2 months of pay stubs\n• Last 2 years of W-2s or tax returns\n• Last 2 months of bank statements\n• Most recent mortgage statement\n\nYou can upload everything securely through your client portal.\n\nWe\'re committed to making your refinance as fast and painless as possible.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(15,1,'App Sent – Refi Day-3 Reminder SMS','SMS reminder 3 days after refinance application received','sms','reminder',NULL,'Hi {{first_name}}, it\'s {{broker_name}} from Encore Mortgage. Just checking in on your refinance app (#{{application_number}}). Have questions or need help with documents? Reply anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(16,1,'App Sent – Refi Day-6 Final SMS','Final SMS nudge 6 days after refinance application received','sms','reminder',NULL,'Hi {{first_name}}! 👋 Your refinance application (#{{application_number}}) is still open. Lock in your rate now — give us a call or reply here. We\'re ready when you are! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(17,1,'App Sent – Default Welcome Email','First email when loan type is not yet classified','email','follow_up','📋 Your Loan Application Has Been Received!','Hi {{first_name}},\n\nWe\'ve received your loan application and our team is reviewing it now.\n\nApplication #: {{application_number}}\n\nNext steps:\n1. Our team will review your details within 1 business day.\n2. We\'ll reach out if we need anything else from you.\n3. You\'ll receive updates throughout the process.\n\nIf you have any questions, just reply to this email or give us a call.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(18,1,'App Sent – Default Day-3 SMS','First SMS reminder 3 days after application received (no loan type)','sms','reminder',NULL,'Hi {{first_name}}, it\'s {{broker_name}} from Encore Mortgage. Checking in on your loan application (#{{application_number}}). Any questions or documents you need help with? Reply anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(19,1,'App Sent – Default Day-10 SMS','Second SMS reminder 10 days after application received (no loan type)','sms','reminder',NULL,'Hi {{first_name}}, we want to make sure your loan application (#{{application_number}}) keeps moving forward. Give us a call or reply here — we\'d love to help! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(20,1,'App Sent – Default Follow-Up Email','Follow-up email 10 days after application (no loan type)','email','follow_up','We\'re Still Here to Help with Your Loan','Hi {{first_name}},\n\nWe noticed your loan application (#{{application_number}}) still has some pending items. We want to make sure you get the best possible outcome.\n\nOur team is ready to walk you through every step — documents, questions, timelines — whatever you need.\n\nWould you be available for a quick call this week? Just reply and we\'ll set it up.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(21,1,'App Sent – Default Day-17 Final SMS','Final SMS reminder 17 days after application (no loan type)','sms','reminder',NULL,'Hi {{first_name}}, last check-in on your loan application (#{{application_number}}). We\'re still here and ready to help. Don\'t let this opportunity pass — reply or call us today! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 21:56:35','2026-03-24 22:36:04'),(22,1,'App Sent – Partner Internal Notification','Internal notification to the assigned partner after default follow-up sequence completes','email','system','[ACTION NEEDED] Loan Application Requires Partner Follow-Up','Hello,\n\nThis is an automated internal alert.\n\nClient {{client_name}} has completed the automated App Sent reminder sequence without responding. Their loan application (#{{application_number}}) may need personal outreach from the assigned partner.\n\nApplication details:\n• Client: {{client_name}}\n• Application #: {{application_number}}\n• Loan Type: {{loan_type}}\n\nPlease follow up directly with the client at your earliest convenience.\n\n— Encore Mortgage Automation','[\"client_name\", \"application_number\", \"loan_type\"]',1,0,1,'2026-03-12 21:56:35','2026-03-12 21:56:35'),(23,1,'App Received – Purchase Welcome SMS','Immediate SMS confirmation when a purchase loan application is received','sms','follow_up',NULL,'Hi {{first_name}}! 🏠 Great news — we received your home purchase application (#{{application_number}}) and our team is already reviewing it. Questions? Just reply! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:45','2026-03-24 22:36:04'),(24,1,'App Received – Purchase Welcome Email','Immediate welcome email for purchase loan once application is fully received','email','follow_up','🏠 We\'ve Received Your Purchase Loan Application!','Hi {{first_name}},\n\nExciting news! Your home purchase loan application has been officially received and is now in our system.\n\nApplication #: {{application_number}}\n\nOur team will begin a thorough review right away. Here\'s what to expect:\n\n• We\'ll contact you within 1 business day with next steps.\n• You may be asked to provide supporting documents through your client portal.\n• We\'ll keep you updated every step of the way.\n\nWe\'re thrilled to be part of your homeownership journey. Don\'t hesitate to reach out with any questions!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-12 22:05:46'),(25,1,'App Received – Purchase 10-Min Follow-Up Email','Follow-up email sent ~10 minutes after application received (purchase)','email','follow_up','What Happens Next with Your Purchase Loan (#{{application_number}})','Hi {{first_name}},\n\nJust following up! Now that we have your application (#{{application_number}}), here\'s a quick checklist of documents you\'ll want to have ready:\n\n✅ Government-issued photo ID (driver\'s license or passport)\n✅ Last 2 months of pay stubs\n✅ Last 2 years of W-2s or tax returns\n✅ Last 2–3 months of bank statements\n✅ Any gift letters (if applicable)\n\nYou can upload everything securely through your client portal. Getting these in early will help us move faster!\n\nReady to chat? Reply to this email or give us a call — we\'re here.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-12 22:05:46'),(26,1,'App Received – Purchase Day-2 Follow-Up SMS','SMS follow-up 2 days after purchase application received','sms','reminder',NULL,'Hi {{first_name}}, it\'s {{broker_name}} from Encore Mortgage. Checking in on your purchase loan app (#{{application_number}}) — have you had a chance to log in to your portal and review your checklist? We\'re here if you need anything!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-24 22:36:04'),(27,1,'App Received – Refi Welcome SMS','Immediate SMS confirmation when a refinance loan application is received','sms','follow_up',NULL,'Hi {{first_name}}! 🔄 We received your refinance application (#{{application_number}}) and are reviewing it now. We\'ll follow up shortly — reply anytime with questions! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-24 22:36:04'),(28,1,'App Received – Refi Welcome Email','Immediate welcome email for refinance loan once application is fully received','email','follow_up','🔄 Your Refinance Application Has Been Received!','Hi {{first_name}},\n\nYour refinance application is officially in — and our team has already started the review process.\n\nApplication #: {{application_number}}\n\nRefinancing is one of the smartest financial moves you can make, and we\'re here to make it seamless.\n\nWhat to expect:\n• We\'ll review your application and reach out within 1 business day.\n• We may request supporting documents through your secure client portal.\n• You\'ll receive updates at key milestones.\n\nHave questions? Just reply to this email — we\'re happy to help.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-12 22:05:46'),(29,1,'App Received – Refi 10-Min Follow-Up Email','Follow-up email sent ~10 minutes after refinance application received','email','follow_up','Quick Checklist for Your Refinance (#{{application_number}})','Hi {{first_name}},\n\nGreat start! To keep your refinance moving as quickly as possible, here are the documents we\'ll need:\n\n✅ Government-issued photo ID\n✅ Last 2 months of pay stubs\n✅ Last 2 years of W-2s or tax returns\n✅ Last 2–3 months of bank statements\n✅ Most recent mortgage statement\n✅ Homeowners insurance declaration page\n\nUpload them securely through your client portal whenever you\'re ready. Getting ahead on documents can save days in processing.\n\nQuestions? We\'re a reply or call away.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-12 22:05:46'),(30,1,'App Received – Refi Day-2 Follow-Up SMS','SMS follow-up 2 days after refinance application received','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} here from Encore Mortgage. Just checking in on your refinance app (#{{application_number}}). Have you had a chance to review your document checklist in the portal? We\'re here to help make this easy!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:05:46','2026-03-24 22:36:04'),(31,1,'Prequalified – Purchase SMS 1','Initial SMS on prequalification (purchase)','sms','follow_up',NULL,'Hi {{first_name}}! 🎉 Great news — you\'ve been prequalified for your home purchase loan (#{{application_number}})! Our team is ready to guide you through the next steps. Questions? Just reply! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(32,1,'Prequalified – Purchase Email 1','Initial welcome email on prequalification (purchase)','email','follow_up','🏠 You\'re Prequalified! Here\'s What\'s Next','Hi {{first_name}},\n\nFantastic news — you\'ve been *prequalified* for your home purchase loan!\n\nApplication #: {{application_number}}\n\nBeing prequalified is a major milestone. Here\'s what comes next:\n\n1. We\'ll review your full application and documents.\n2. A formal pre-approval letter will follow once we confirm your details.\n3. You\'ll be in a strong position to make offers on homes!\n\nIf you have any questions or want to discuss your options, just reply to this email — we\'re here every step of the way.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(33,1,'Prequalified – Purchase SMS 2','Day-2 follow-up SMS (purchase)','sms','reminder',NULL,'Hi {{first_name}}, it\'s {{broker_name}} from Encore Mortgage. You\'re prequalified for your home purchase (#{{application_number}}) — don\'t let this momentum slow down! Ready to talk next steps? Reply here or give us a call.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(34,1,'Prequalified – Purchase SMS 3','Day-4 check-in SMS (purchase)','sms','reminder',NULL,'Hi {{first_name}}! 👋 Quick check-in from {{broker_name}} at Encore Mortgage. Your prequalification for loan #{{application_number}} is still active. Are you actively looking for homes? We can help you move fast when you find the one. Reply anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(35,1,'Prequalified – Purchase Email 2','Day-4 follow-up email with resources (purchase)','email','follow_up','Still Looking for the Right Home? We\'re Here When You\'re Ready','Hi {{first_name}},\n\nJust circling back on your prequalification (#{{application_number}}).\n\nWe know home shopping takes time — and we want you to know we\'re here whenever you\'re ready to move forward. Whether you have questions about the process, want to understand your buying power, or are ready to lock in your rate, we\'re just a reply away.\n\nA few things to keep in mind:\n• Your prequalification is still active.\n• Interest rates can change — locking in sooner can save you money.\n• We can issue a pre-approval letter the moment you find the right home.\n\nLet\'s keep this moving!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(36,1,'Prequalified – Purchase SMS 4','Day-7 nudge SMS (purchase)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} here. Your home purchase prequalification (#{{application_number}}) is ready and waiting! Once you find a home you love, we can move quickly. Have questions about your max purchase price or next steps? Reply and I\'ll help!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(37,1,'Prequalified – Purchase SMS 5','Day-11 re-engagement SMS (purchase)','sms','reminder',NULL,'Hey {{first_name}}! 🏡 Still thinking about buying a home? Your prequalification (#{{application_number}}) is still active. I\'d love to help you get to the finish line. Let\'s connect — reply or call me today! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(38,1,'Prequalified – Purchase Email 3','Day-14 re-engagement email (purchase)','email','follow_up','Your Home Purchase Prequalification Is Still Active — Let\'s Talk','Hi {{first_name}},\n\nI wanted to personally reach out regarding your prequalification (#{{application_number}}).\n\nBuying a home is one of the biggest decisions you\'ll make — and I want to make sure you feel fully supported. If anything has changed in your situation, or if you have concerns about the process, I\'m here to help.\n\nAre you:\n• Still searching for the right home?\n• Unsure about your budget or buying power?\n• Waiting on something specific before moving forward?\n\nJust reply to this email and let\'s have a quick conversation. No pressure — just here to help.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(39,1,'Prequalified – Purchase SMS 6','Day-17 final SMS before last sequence (purchase)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} from Encore Mortgage. I\'ve been trying to connect about your home purchase prequalification (#{{application_number}}). I\'d love to help make your homeownership dream a reality. This is my last automated check-in — reply anytime and I\'ll pick it right up!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(40,1,'Prequalified – Purchase SMS 7','Day-20 final attempt SMS (purchase)','sms','reminder',NULL,'Hi {{first_name}}, one final note from {{broker_name}} at Encore Mortgage about your home purchase prequalification (#{{application_number}}). Rates are always moving — if you\'re ready to act, we\'re ready to move fast for you. Reply or call us today.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(41,1,'Prequalified – Purchase Email 4','Day-25 final email before internal notification (purchase)','email','follow_up','A Final Note on Your Home Purchase Prequalification','Hi {{first_name}},\n\nThis is our final automated message regarding your home purchase prequalification (#{{application_number}}).\n\nWe\'ve reached out several times and want to make sure you know we\'re still here. If now isn\'t the right time, that\'s completely okay — just know that when you\'re ready, we\'ll be ready too.\n\nFeel free to reach out at any time. Your prequalification can be updated and a pre-approval can be issued quickly when the moment is right.\n\nWishing you all the best,\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(42,1,'Prequalified – Refi SMS 1','Initial SMS on prequalification (refi)','sms','follow_up',NULL,'Hi {{first_name}}! 🔄 You\'ve been prequalified for your refinance (#{{application_number}})! We\'re ready to help you lock in a better rate or access your equity. Questions? Reply anytime! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(43,1,'Prequalified – Refi Email 1','Initial welcome email on prequalification (refi)','email','follow_up','🔄 You\'re Prequalified to Refinance — Here\'s What\'s Next','Hi {{first_name}},\n\nExcellent news — you\'ve been *prequalified* for your refinance!\n\nApplication #: {{application_number}}\n\nYour prequalification means we\'ve reviewed your initial information and you\'re in a great position to move forward. Here\'s what to expect next:\n\n1. We\'ll complete a full review of your application.\n2. An appraisal may be required depending on your loan program.\n3. We\'ll guide you through locking in your rate at the right moment.\n\nRefinancing now could mean significant monthly savings. Let\'s get this done!\n\nReply to this email with any questions — we\'re ready to move quickly.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(44,1,'Prequalified – Refi SMS 2','Day-2 follow-up SMS (refi)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} from Encore Mortgage here. Your refinance prequalification (#{{application_number}}) is ready to move forward. Rates are shifting — locking in now could save you thousands. Ready to take the next step? Reply here!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(45,1,'Prequalified – Refi SMS 3','Day-4 check-in SMS (refi)','sms','reminder',NULL,'Hi {{first_name}}! Quick check-in from {{broker_name}} at Encore Mortgage. Your refinance prequalification (#{{application_number}}) is active and your potential savings are waiting. Have questions about the process or your rate options? Just reply!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(46,1,'Prequalified – Refi Email 2','Day-4 follow-up email (refi)','email','follow_up','Your Refinance Prequalification Is Active — Don\'t Miss This Window','Hi {{first_name}},\n\nFollowing up on your refinance prequalification (#{{application_number}}).\n\nWith rates constantly changing, acting sooner rather than later can make a real difference in your monthly payment and total interest paid. Here\'s a quick snapshot of how refinancing can help:\n\n💰 Lower your monthly payment\n🔒 Lock in a fixed rate for stability\n💵 Access home equity for renovations or debt consolidation\n📅 Shorten your loan term\n\nWe can run the numbers with you at no cost. Just reply and we\'ll set up a quick call.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(47,1,'Prequalified – Refi SMS 4','Day-7 nudge SMS (refi)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} here from Encore Mortgage. Still thinking about your refinance (#{{application_number}})? No pressure — but I want to make sure you don\'t miss out on a favorable rate. I\'m here whenever you\'re ready. Reply anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(48,1,'Prequalified – Refi SMS 5','Day-11 re-engagement SMS (refi)','sms','reminder',NULL,'Hey {{first_name}}! 💰 Your refinance prequalification (#{{application_number}}) is still open. Homeowners who refinance at the right time can save hundreds per month. Let\'s find out what\'s possible for you — reply or call me today! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(49,1,'Prequalified – Refi Email 3','Day-14 re-engagement email (refi)','email','follow_up','Still Thinking About Refinancing? Let\'s Talk','Hi {{first_name}},\n\nI wanted to personally reach out about your refinance prequalification (#{{application_number}}).\n\nI understand refinancing can feel like a big decision. I\'m here to simplify it for you and make sure you\'re making the best move for your financial situation.\n\nSome questions I can help answer:\n• How much could I save monthly by refinancing?\n• Is now a good time to lock in a rate?\n• What documents will I need?\n• How long does the process take?\n\nJust reply to this email and let\'s get on a quick 10-minute call. There\'s no obligation — just clarity.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(50,1,'Prequalified – Refi SMS 6','Day-17 final SMS before last sequence (refi)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} from Encore Mortgage. I\'ve been following up on your refinance prequalification (#{{application_number}}) and I really want to help. This is my last automated message — reply anytime and I\'ll be happy to pick up right where we left off.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(51,1,'Prequalified – Refi SMS 7','Day-20 final attempt SMS (refi)','sms','reminder',NULL,'Hi {{first_name}}, one final note from {{broker_name}} at Encore Mortgage on your refinance prequalification (#{{application_number}}). Whether you want to lower your rate, reduce your term, or tap equity — we\'re ready when you are. Call or reply today.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-24 22:36:04'),(52,1,'Prequalified – Refi Email 4','Day-25 final email before internal notification (refi)','email','follow_up','A Final Note on Your Refinance Prequalification','Hi {{first_name}},\n\nThis is our final automated message about your refinance prequalification (#{{application_number}}).\n\nWe\'ve genuinely enjoyed the opportunity to work with you and hope we\'ll hear from you when the time is right. Refinancing is always on the table — rates and programs change, and we\'ll be here.\n\nIf you ever want a fresh look at your options, don\'t hesitate to reach out.\n\nWishing you all the best,\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(53,1,'Prequalified – Internal All-User Notification','Internal notification to all users after full prequalified sequence without response','email','system','[ACTION NEEDED] Prequalified Client Has Not Responded — Full Sequence Completed','Hello Team,\n\nThis is an automated internal alert.\n\nClient {{client_name}} completed the full Prequalified automated reminder sequence without responding. Personal outreach is now recommended.\n\nApplication Details:\n• Client: {{client_name}}\n• Application #: {{application_number}}\n• Loan Type: {{loan_type}}\n• Status: Prequalified\n\nPlease coordinate internally and assign a team member to follow up directly.\n\n— Encore Mortgage Automation','[\"client_name\", \"application_number\", \"loan_type\"]',1,0,1,'2026-03-12 22:34:43','2026-03-12 22:34:43'),(54,1,'Preapproved – Purchase SMS 1','Initial SMS on pre-approval (purchase)','sms','follow_up',NULL,'Hi {{first_name}}! 🏡 Big news — you\'ve been *pre-approved* for your home purchase loan (#{{application_number}})! This is a major step. Your pre-approval letter is ready and you can start making offers confidently. Questions? Reply anytime! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(55,1,'Preapproved – Purchase Email 1','Initial welcome email on pre-approval (purchase)','email','follow_up','🎉 Congratulations — You\'re Pre-Approved to Buy a Home!','Hi {{first_name}},\n\nExciting news — you have been officially *pre-approved* for your home purchase loan!\n\nApplication #: {{application_number}}\n\nThis is a significant milestone. Here\'s what your pre-approval means for you:\n\n✅ You know exactly how much you can borrow\n✅ Sellers will take your offers seriously\n✅ We can issue your pre-approval letter the moment you need it\n✅ You\'re one step closer to the keys!\n\nHere\'s what comes next:\n1. Start touring homes confidently within your budget.\n2. When you find the one, notify us immediately — we move fast.\n3. We\'ll guide you through the offer, appraisal, and closing process.\n\nHave questions about your pre-approval or the buying process? Reply to this email — we\'re here for you.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(56,1,'Preapproved – Refi SMS 1','Initial SMS on pre-approval (refi)','sms','follow_up',NULL,'Hi {{first_name}}! 🔄 Great news — you\'ve been *pre-approved* for your refinance (#{{application_number}})! We\'re ready to lock in your rate and move forward. Want to schedule a quick call to review your options? Reply here! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(57,1,'Preapproved – Refi Email 1','Initial welcome email on pre-approval (refi)','email','follow_up','🎉 Congratulations — You\'re Pre-Approved to Refinance!','Hi {{first_name}},\n\nGreat news — you\'ve been officially *pre-approved* for your refinance!\n\nApplication #: {{application_number}}\n\nHere\'s what this means for you:\n\n💰 Your new rate and payment have been estimated\n🔒 You\'re ready to lock in your rate at any time\n📋 We\'ve reviewed your financials and documents look good\n⚡ We can move quickly once you give the go-ahead\n\nNext steps:\n1. Review your pre-approval terms (we\'ll walk you through them).\n2. Decide when you\'d like to lock in your rate.\n3. Authorize us to order the appraisal if applicable.\n\nRefinancing now could reduce your monthly payment, shorten your loan term, or give you access to cash equity. Let\'s get this done!\n\nReply to this email with any questions.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(58,1,'Preapproved – SMS Follow-Up 02','Day-2 check-in SMS','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} here from Encore Mortgage. Just checking in on your pre-approval (#{{application_number}}). Do you have any questions or need help with the next steps? We\'re ready to move fast when you are. Reply anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(59,1,'Preapproved – SMS Follow-Up 03','Day-4 SMS (before email)','sms','reminder',NULL,'Hey {{first_name}}! Quick reminder from {{broker_name}} at Encore Mortgage — your pre-approval (#{{application_number}}) is active and ready. Are you actively working with a realtor? I can recommend one if needed or help coordinate the offer process. Just reply!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(60,1,'Preapproved – Email Follow-Up 02','Day-4 email follow-up','email','follow_up','Your Pre-Approval Is Active — Here\'s How We Can Help You Move Faster','Hi {{first_name}},\n\nJust following up on your pre-approval (#{{application_number}}).\n\nWe know the home search can take time — and we\'re here to support you through every step.\n\nHere\'s how Encore Mortgage can help you move faster:\n\n🏡 We can issue pre-approval letters on demand (even on weekends)\n📞 We\'re available to speak with listing agents to strengthen your offer\n⚡ We offer fast closings that sellers love\n📊 We can run updated rate scenarios based on your target price range\n\nJust reply or call us whenever you\'re ready. We move at your pace!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(61,1,'Preapproved – SMS Follow-Up 04','Day-6 SMS (before wait3d)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} from Encore Mortgage. Your pre-approval (#{{application_number}}) is still fully active. Remember — sellers love buyers who already have pre-approval in hand! Let us know if you need a letter for a specific property. Reply anytime.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(62,1,'Preapproved – SMS Follow-Up 05','Day-9 SMS (after wait3d)','sms','reminder',NULL,'Hi {{first_name}}! 👋 {{broker_name}} here. Checking in again on your pre-approval (#{{application_number}}). Have you found any properties you\'re interested in? Even if you\'re just starting to look, I can help you understand what fits your budget. Reply and let\'s chat!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(63,1,'Preapproved – Email Follow-Up 03','Day-9 email follow-up','email','follow_up','Tips for Making the Most of Your Pre-Approval','Hi {{first_name}},\n\nI wanted to share a few tips to help you make the most of your pre-approval (#{{application_number}}) while you search for the right home.\n\n**Do\'s while your pre-approval is active:**\n✅ Continue monitoring listings in your target area\n✅ Keep your finances stable (avoid large purchases or new credit)\n✅ Stay in touch with your realtor on new inventory\n✅ Contact us immediately when you find a home you want to offer on\n\n**Don\'ts:**\n❌ Don\'t open new credit cards or take on new debt\n❌ Don\'t change jobs without letting us know\n❌ Don\'t make large cash deposits without documentation\n\nKeeping these in mind will help ensure a smooth closing when the time comes. Any questions? I\'m always here.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(64,1,'Preapproved – SMS Follow-Up 06','Day-12 SMS (after wait3d, before email)','sms','reminder',NULL,'Hi {{first_name}}, it\'s {{broker_name}} from Encore Mortgage. Still thinking about your loan (#{{application_number}})? Rates can change week to week — if you\'re close to making an offer, now might be a great time to discuss locking in your rate. Reply or call me today!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(65,1,'Preapproved – Email Follow-Up 04','Day-12 email follow-up','email','follow_up','Have You Considered Locking In Your Rate?','Hi {{first_name}},\n\nFollowing up on your pre-approval (#{{application_number}}).\n\nOne of the most important decisions in your mortgage journey is *when* to lock in your rate. A rate lock protects you from increases while you finalize your home purchase or refinance.\n\nHere\'s what you should know:\n\n📌 Rate locks are typically 30–60 days\n📌 Locking in now could protect you from rising rates\n📌 We monitor the market daily to advise the best timing\n\nWould you like to discuss your rate lock options? Just reply to this email or give me a call and we\'ll walk through the numbers together.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(66,1,'Preapproved – SMS Follow-Up 07','Day-15 SMS (after wait3d)','sms','reminder',NULL,'Hey {{first_name}}! 📲 {{broker_name}} from Encore Mortgage. Two weeks since your pre-approval (#{{application_number}}) — just wanted to check in. Is there anything we can do to help your home search move forward? We\'re here to support you however we can. Reply!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(67,1,'Preapproved – SMS Follow-Up 08','Day-17 SMS (after wait2d)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} here. Just a quick note — your pre-approval (#{{application_number}}) is still ready for action. The market moves fast; when you\'re ready to make an offer, we can provide a same-day pre-approval letter. Don\'t hesitate to reach out!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(68,1,'Preapproved – SMS Follow-Up 09','Day-19 SMS (after wait2d)','sms','reminder',NULL,'Hi {{first_name}}! {{broker_name}} from Encore Mortgage checking in. It\'s been a couple of weeks since your pre-approval (#{{application_number}}). How\'s the home search going? Whether you\'re close to an offer or still browsing, I\'m here to help. Reply anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(69,1,'Preapproved – SMS Follow-Up 10','Day-21 SMS (after wait2d)','sms','reminder',NULL,'Hello {{first_name}}! Quick check from {{broker_name}} at Encore Mortgage. Your pre-approval (#{{application_number}}) is still active. If you\'ve been hesitant about the process or costs, let\'s talk — I can walk you through everything with no pressure. Reply here!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(70,1,'Preapproved – SMS Follow-Up 11','Day-23 SMS (after wait2d)','sms','reminder',NULL,'Hi {{first_name}}, {{broker_name}} from Encore Mortgage. I know life gets busy — just a friendly reminder that your pre-approval (#{{application_number}}) is still here and ready. When you find the right home, we\'ll be ready to move instantly. Reply or call anytime!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(71,1,'Preapproved – SMS Follow-Up 12','Day-28 SMS (after wait5d, before email)','sms','reminder',NULL,'Hi {{first_name}}! It\'s been about 4 weeks since your pre-approval (#{{application_number}}). {{broker_name}} here from Encore Mortgage — I just wanted to personally check in. Have your needs or circumstances changed? I can update your pre-approval at any time. Reply here or call me!','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-24 22:36:04'),(72,1,'Preapproved – Email Follow-Up 05','Day-28 email (after wait5d)','email','follow_up','One Month In — Your Pre-Approval Remains Ready','Hi {{first_name}},\n\nA month has passed since your pre-approval (#{{application_number}}), and we\'re still here cheering you on!\n\nWe understand that finding the right home takes time, and we never want to rush a decision this important. But we do want to make sure you have all the support you need.\n\nA few things worth knowing at this stage:\n\n📅 Pre-approvals are typically valid for 60–90 days from the credit check date. If yours is approaching expiration, we can refresh it quickly with a soft update.\n\n📊 Have your income, employment, or finances changed? Let us know and we\'ll update your file accordingly.\n\n🏠 If you\'ve been looking at properties outside your current pre-approved range, we can explore options.\n\nJust reply to this email and let\'s review where things stand.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(73,1,'Preapproved – Email Follow-Up 06','Day-38 email (after wait10d)','email','follow_up','Week 5 Check-In: Your Mortgage Questions Answered','Hi {{first_name}},\n\nHope you\'re well! We\'re still here to support your loan process (#{{application_number}}).\n\nWe thought we\'d take a moment to answer some of the most common questions we hear at this stage:\n\n**Q: Is my pre-approval letter still valid?**\nA: Pre-approvals are typically good for 60–90 days. Let us know if you\'re approaching that window.\n\n**Q: What if I find a home over my pre-approved amount?**\nA: We can review your financials and potentially increase your pre-approval. Just reach out.\n\n**Q: How quickly can we close once I have a signed contract?**\nA: We strive for 21–30 day closings for our prepared clients like you.\n\n**Q: What if interest rates have changed since my pre-approval?**\nA: We\'ll run updated numbers before you make an offer — no surprises.\n\nHave a question not listed here? Just reply — we\'re happy to help.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(74,1,'Preapproved – Email Follow-Up 07','Day-48 email (after wait10d)','email','follow_up','Week 7 — Still Here, Still Ready to Help You Close','Hi {{first_name}},\n\nJust checking in on your loan file #{{application_number}}.\n\nWe know life happens — whether it\'s been a competitive market, shifting personal priorities, or simply taking the time to find the right fit, we\'re here without judgment.\n\nAt Encore Mortgage, our goal is simple: to be your trusted partner when you\'re ready to move. There\'s no pressure and no deadline from our side.\n\nThat said, if there\'s anything slowing you down — financing questions, budget concerns, or uncertainty about the process — we\'d love to help clear it up.\n\nJust hit reply and let\'s talk.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(75,1,'Preapproved – Email Follow-Up 08','Day-63 email (after wait15d)','email','follow_up','Two Months Since Your Pre-Approval — Let\'s Reconnect','Hi {{first_name}},\n\nIt\'s been about two months since your pre-approval for loan #{{application_number}}.\n\nWe want to be straightforward with you: pre-approvals have an expiration date, and if yours is close to expiring, we\'d recommend we reconnect to refresh your file. This is typically a quick and painless process.\n\nHere\'s what a refreshed pre-approval means:\n✅ Updated rate quotes based on current market conditions\n✅ Confirms your financial picture is still on track\n✅ Gives you renewed confidence heading into offers\n\nAlternatively, if your plans have changed or if this simply isn\'t the right time, we understand completely — just let us know so we can properly update your file.\n\nReply to this email to reconnect. We\'d love to hear from you.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(76,1,'Preapproved – Email Follow-Up 09','Day-73 email (after wait10d)','email','follow_up','Week 10 — A Personal Note From Your Loan Officer','Hi {{first_name}},\n\nI wanted to reach out personally about your loan file #{{application_number}}.\n\nYour pre-approval was an important step and I\'ve been following your file closely. I know the home buying (or refinancing) journey can be full of unexpected twists, and I want you to know I\'m in your corner.\n\nIf there\'s anything — questions, concerns, change in plans, or if you\'re finally ready to move — please don\'t hesitate to reply or call me directly.\n\nYour goals matter to us. We\'re not just processing loans — we\'re helping families achieve something meaningful. I\'d be honored to help you get to the finish line.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(77,1,'Preapproved – Email Follow-Up 10','Day-88 email (after wait15d)','email','follow_up','Final Reminder: Your Pre-Approval May Be Expiring Soon','Hi {{first_name}},\n\nThis is an important update regarding your pre-approval for loan #{{application_number}}.\n\nMost pre-approvals are valid for 60–90 days from the initial credit check. If we haven\'t reconnected recently, your pre-approval may be approaching or have passed its expiration date.\n\nThis doesn\'t mean you\'re out of options — it simply means we\'ll need to do a quick refresh of your file to issue a current pre-approval letter.\n\nOptions moving forward:\n1. **Renew your pre-approval** — quick process, usually same-day\n2. **Update your file** if circumstances have changed\n3. **Let us know if you\'d like to pause** — we\'ll note your file accordingly\n\nPlease reply to this email so we can best support you from here.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(78,1,'Preapproved – Email Final','Final email after full sequence (no wait before this)','email','follow_up','We\'re Here Whenever You\'re Ready — No Pressure','Hi {{first_name}},\n\nThis is our final automated message regarding your pre-approval for loan #{{application_number}}.\n\nWe\'ve reached out multiple times over the past few months because we genuinely believe in helping you achieve your goals. But we also respect your timeline and understand that life has its own pace.\n\nWhenever you\'re ready — whether it\'s tomorrow or six months from now — we will be here. Just reach out and we\'ll pick up right where we left off.\n\nThank you for giving Encore Mortgage the opportunity to serve you. We look forward to celebrating your success when the time is right.\n\nWarm regards,\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:47:43','2026-03-12 22:47:43'),(79,1,'Under Contract/Loan Set Up – SMS','Immediate SMS when loan enters Under Contract / Loan Set Up status','sms','follow_up',NULL,'Hi {{first_name}}! 🎉 Congratulations — you\'re officially under contract! Your loan (#{{application_number}}) is now in the setup phase and we\'re working hard to keep things moving. We\'ll keep you updated every step of the way. Questions? Reply anytime! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:50:22','2026-03-24 22:36:04'),(80,1,'Under Contract/Loan Set Up – Email','Immediate email when loan enters Under Contract / Loan Set Up status','email','follow_up','🏡 You\'re Under Contract — Here\'s What Happens Next','Hi {{first_name}},\n\nCongratulations — you\'re officially under contract! This is an exciting milestone, and our team at Encore Mortgage is fully focused on making your closing as smooth as possible.\n\nApplication #: {{application_number}}\n\nHere\'s what we\'re working on during the Loan Set Up phase:\n\n📋 **Loan File Review** — We\'re organizing and verifying all your documentation.\n🏠 **Appraisal Coordination** — We\'ll be ordering or scheduling your home appraisal shortly.\n🔒 **Rate Lock** — If you haven\'t locked your rate yet, now is the time. Let\'s discuss!\n📑 **Title & Escrow** — We\'re coordinating with title and escrow to ensure a clean transaction.\n\n**What you need to do right now:**\n1. Avoid opening new lines of credit or making large purchases.\n2. Keep your employment and income situation stable.\n3. Respond quickly to any document requests from our team — speed matters!\n4. Keep your phone and email accessible; we may need to reach you quickly.\n\n**Your estimated closing timeline** starts from today. We\'ll provide regular updates as we move through underwriting and approvals.\n\nIf you have any questions at any point, please don\'t hesitate to reach out. We\'re here for you through every step.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:50:22','2026-03-12 22:50:22'),(81,1,'Submitted to Underwriting – SMS','Immediate SMS when loan is submitted to underwriting','sms','follow_up',NULL,'Hi {{first_name}}! 📋 Great news — your loan (#{{application_number}}) has been submitted to underwriting! This is a key milestone. Our underwriters will review your full file and we\'ll keep you posted on any updates. Hang tight — we\'re on it! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:51:53','2026-03-24 22:36:04'),(82,1,'Submitted to Underwriting – Email','Immediate email when loan is submitted to underwriting','email','follow_up','📋 Your Loan Has Been Submitted to Underwriting','Hi {{first_name}},\n\nWe have an important update on your loan (#{{application_number}}) — your file has been officially submitted to underwriting!\n\nThis is one of the most critical stages of the mortgage process, and we want to make sure you know exactly what to expect.\n\n**What is underwriting?**\nAn underwriter is a specialist who thoroughly reviews your loan file — including your income, assets, credit, and the property details — to make a final lending decision.\n\n**What happens during underwriting:**\n🔍 **Document Review** — The underwriter will verify all submitted documents.\n🏡 **Appraisal Review** — The property appraisal will be evaluated against the loan amount.\n💳 **Credit & Income Analysis** — Employment, income, and credit history are assessed in detail.\n⚖️ **Risk Assessment** — The underwriter determines if the loan meets all program guidelines.\n\n**Typical underwriting timeline:** 3–7 business days (can vary based on file complexity and lender volume).\n\n**What you can do to help speed things up:**\n✅ Respond immediately to any requests for additional documents or explanations.\n✅ Do NOT make any major financial changes — no new credit, large purchases, or job changes.\n✅ Keep your phone and email accessible in case we need to reach you urgently.\n✅ If you receive a \"Conditions\" list, gather those items as fast as possible.\n\n**What comes after underwriting?**\nOnce the underwriter reviews your file, you\'ll receive one of three outcomes:\n- ✅ **Approved** — Congratulations! We move to closing.\n- ⚠️ **Approved with Conditions** — Minor items needed before final approval.\n- ❌ **Suspended/Denied** — We\'ll discuss options if this happens (it\'s rare for well-prepared files like yours).\n\nWe\'re working hard and will keep you updated. If you have any questions in the meantime, don\'t hesitate to reach out.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:51:53','2026-03-12 22:51:53'),(83,1,'Approved with Conditions – SMS','Immediate SMS when loan is approved with conditions','sms','follow_up',NULL,'Hi {{first_name}}! 🎉 Your loan (#{{application_number}}) has been *approved with conditions*! This means the underwriter has approved your loan pending a few items we need to clear. We\'ll send you details by email shortly. Don\'t worry — this is very common and we\'ll guide you through every item. – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:55:02','2026-03-24 22:36:04'),(84,1,'Approved with Conditions – Email','Immediate email when loan is approved with conditions','email','follow_up','✅ Your Loan Is Approved — With Conditions','Hi {{first_name}},\n\nGreat news — your loan (#{{application_number}}) has been reviewed by underwriting and you have been issued an **Approval with Conditions**!\n\nThis is a very common and positive outcome. It means the underwriter has approved your loan in principle, but requires a few additional items before issuing a final clear-to-close.\n\n**What \"Approved with Conditions\" means:**\n✅ The core of your loan file has passed underwriting review.\n⚠️ There are specific conditions (items) that must be satisfied before final approval.\n📋 Once all conditions are cleared, you\'ll receive a \"Clear to Close\" — the final milestone before signing!\n\n**Common conditions may include:**\n• Additional income documentation (pay stubs, tax returns, letters of explanation)\n• Updated bank statements\n• Clarification letters on large deposits or inquiries\n• Homeowner\'s insurance confirmation\n• Title commitments or HOA documents\n• Property repair requirements from the appraisal\n\n**What you need to do RIGHT NOW:**\n1. Watch for a follow-up message or call from our team with your specific conditions list.\n2. Gather and submit the required documents as quickly as possible — speed is critical at this stage.\n3. Do NOT make any financial changes — no new credit, large purchases, or job changes.\n4. Contact your homeowner\'s insurance agent immediately if not already done.\n\n**Timeline:** Once all conditions are submitted and reviewed, final approval typically happens within 1–3 business days.\n\nWe\'re so close to the finish line! Our team is working hard on your behalf. If you have any questions about your specific conditions, please reply or call us right away.\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:55:02','2026-03-12 22:55:02'),(85,1,'Approved with Conditions – Notify Buyer Agent (Internal)','Internal notification to contact the buyer\'s agent about the approval with conditions','email','system','[ACTION] Notify Buyer Agent — Loan Approved with Conditions','Hello Team,\n\nThis is an automated internal alert.\n\nLoan #{{application_number}} for client {{client_name}} has been **Approved with Conditions** by underwriting.\n\nAction Required: Please contact the **Buyer\'s Agent** immediately to inform them of the conditional approval and update them on the conditions that need to be cleared before a Clear to Close can be issued.\n\nKey points to communicate to the Buyer\'s Agent:\n• The loan has passed underwriting review with conditions\n• Conditions must be cleared promptly to meet the closing timeline\n• Any cooperation needed (e.g. addenda, HOA docs) should be addressed immediately\n• Keep the seller\'s agent informed as needed to avoid closing delays\n\nLoan Details:\n• Client: {{client_name}}\n• Application #: {{application_number}}\n• Loan Type: {{loan_type}}\n• Status: Approved with Conditions\n\nPlease log your outreach in the system once completed.\n\n— Encore Mortgage Automation','[\"client_name\", \"application_number\", \"loan_type\"]',1,0,1,'2026-03-12 22:55:02','2026-03-12 22:55:02'),(86,1,'Approved with Conditions – Notify Listing Agent (Internal)','Internal notification to contact the listing agent about the approval with conditions','email','system','[ACTION] Notify Listing Agent — Loan Approved with Conditions','Hello Team,\n\nThis is an automated internal alert.\n\nLoan #{{application_number}} for client {{client_name}} has been **Approved with Conditions** by underwriting.\n\nAction Required: Please contact the **Listing Agent** to inform them of the current loan status and manage expectations around the closing timeline.\n\nKey points to communicate to the Listing Agent:\n• The loan is progressing and has received a conditional approval\n• Conditions are being worked on and we expect to clear them promptly\n• We are committed to meeting the agreed closing date\n• If any contract extensions or accommodations are needed, they should be discussed now\n\nLoan Details:\n• Client: {{client_name}}\n• Application #: {{application_number}}\n• Loan Type: {{loan_type}}\n• Status: Approved with Conditions\n\nPlease log your outreach in the system once completed.\n\n— Encore Mortgage Automation','[\"client_name\", \"application_number\", \"loan_type\"]',1,0,1,'2026-03-12 22:55:02','2026-03-12 22:55:02'),(87,1,'Approved with Conditions – Notify Title Agent (Internal)','Internal notification to contact the title agent about the approval with conditions','email','system','[ACTION] Notify Title Agent — Loan Approved with Conditions','Hello Team,\n\nThis is an automated internal alert.\n\nLoan #{{application_number}} for client {{client_name}} has been **Approved with Conditions** by underwriting.\n\nAction Required: Please contact the **Title Agent / Title Company** to ensure all title-related conditions are on their radar and to coordinate any outstanding title requirements.\n\nKey points to communicate to the Title Agent:\n• Loan is in conditional approval status — a Clear to Close is pending\n• Confirm the title commitment is current and all requirements have been submitted to underwriting\n• Verify any lien releases, HOA certifications, or survey items have been addressed\n• Confirm the title company is ready to schedule closing upon CTC issuance\n• Request a preliminary Closing Disclosure (CD) if not yet prepared\n\nLoan Details:\n• Client: {{client_name}}\n• Application #: {{application_number}}\n• Loan Type: {{loan_type}}\n• Status: Approved with Conditions\n\nPlease log your outreach in the system once completed.\n\n— Encore Mortgage Automation','[\"client_name\", \"application_number\", \"loan_type\"]',1,0,1,'2026-03-12 22:55:03','2026-03-12 22:55:03'),(88,1,'Clear to Close – SMS','Immediate SMS when loan reaches Clear to Close status','sms','follow_up',NULL,'Hi {{first_name}}! 🎉🏡 YOU ARE CLEAR TO CLOSE! Your loan (#{{application_number}}) has officially been cleared by underwriting — this is the final green light! We\'re scheduling your closing now and will send you all the details. Get ready to sign and celebrate! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:57:51','2026-03-24 22:36:04'),(89,1,'Clear to Close – Purchase Email','Clear to Close email for home purchase loans','email','follow_up','🎉 Clear to Close — You\'re Almost a Homeowner!','Hi {{first_name}},\n\nThis is the message you\'ve been waiting for — your loan (#{{application_number}}) is officially **Clear to Close**!\n\nUnderwriting has completed its review, all conditions have been satisfied, and you are cleared to sign your closing documents. You are about to become a homeowner — congratulations!\n\n**What \"Clear to Close\" means:**\n✅ All loan conditions have been fully satisfied\n✅ The lender has given final approval\n✅ Your loan is ready to fund at closing\n✅ You\'re one signing appointment away from getting your keys!\n\n**What happens next — your closing checklist:**\n\n📋 **Review your Closing Disclosure (CD)**\nYou should have received (or will receive soon) a Closing Disclosure with the final loan terms, monthly payment, and all closing costs. Review it carefully. You have the right to review this document at least 3 business days before closing.\n\n💰 **Prepare your closing funds**\nYour CD will show the exact amount you need to bring to closing. This must typically be wired or brought as a cashier\'s check — personal checks are usually NOT accepted. Contact us right away if you have questions about this amount.\n\n🪪 **Bring a valid government-issued photo ID**\nYou\'ll need this to sign your closing documents. Make sure your name matches exactly what\'s on the loan documents.\n\n🏠 **Final walkthrough**\nCoordinate with your realtor to do a final walkthrough of the property before your closing appointment — ideally the day before or morning of closing.\n\n📞 **Do NOT make any financial changes**\nUntil the loan has funded and recorded, please avoid any new credit, large purchases, job changes, or large bank transfers. Even at this stage, these can delay or jeopardize your closing.\n\n**Your closing appointment details** will be confirmed by our team shortly. Please keep your schedule flexible and respond promptly to any final requests.\n\nThank you for trusting Encore Mortgage with your home purchase. We\'re so excited to hand you the keys!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:57:51','2026-03-12 22:57:51'),(90,1,'Clear to Close – Refi Email','Clear to Close email for refinance loans','email','follow_up','🎉 Clear to Close — Your Refinance Is Almost Done!','Hi {{first_name}},\n\nFantastic news — your refinance loan (#{{application_number}}) is officially **Clear to Close**!\n\nUnderwriting has given the final approval and all conditions have been satisfied. We\'re now in the home stretch — just a signing appointment stands between you and your new loan!\n\n**What \"Clear to Close\" means for your refinance:**\n✅ All conditions have been cleared\n✅ Your new interest rate and loan terms are locked and confirmed\n✅ The lender is ready to fund\n✅ You\'re about to start saving on your mortgage!\n\n**What happens next — your refinance closing checklist:**\n\n📋 **Review your Closing Disclosure (CD)**\nYou should receive a final Closing Disclosure with your new loan terms, closing costs, and any cash out or cash in required at closing. Review it carefully — you have 3 business days to review before we can close.\n\n💰 **Closing costs / cash to close**\nFor most refinances, closing costs are either rolled into the loan or deducted from proceeds. Your CD will show exactly what (if anything) you need to bring or will receive. Let us know if you have questions.\n\n📅 **Right of Rescission (if applicable)**\nFor owner-occupied refinances (non-purchase), federal law gives you 3 business days after signing to cancel the transaction if you change your mind. Your loan will not fund until this period has passed.\n\n🪪 **Bring a valid government-issued photo ID**\nTo sign your closing documents, you\'ll need a current, valid photo ID matching your name on the loan.\n\n📞 **Do NOT make any financial changes**\nUntil your loan has funded and recorded, avoid any changes to your finances — no new credit, large purchases, or job changes.\n\n**Your signing appointment details** will be confirmed shortly. A notary or title agent will coordinate with you directly.\n\nThank you for choosing Encore Mortgage for your refinance. We look forward to completing this transaction and delivering your savings!\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 22:57:51','2026-03-12 22:57:51'),(91,1,'Loan Funded – SMS','SMS sent on the close date when the loan funds','sms','follow_up',NULL,'Hi {{first_name}}! 🎉🔑 YOUR LOAN HAS FUNDED! Congratulations — your loan (#{{application_number}}) is officially closed and the keys are yours! It has been a pleasure working with you. Wishing you many happy years in your new home! – {{broker_name}}, Encore Mortgage.','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 23:02:15','2026-03-24 22:36:04'),(92,1,'Loan Funded – Email','Email sent on the close date when the loan funds','email','follow_up','🎉 Your Loan Has Funded — Congratulations!','Hi {{first_name}},\n\nThis is the moment you\'ve been working toward — **your loan has officially funded and closed!** 🎊\n\nApplication #: {{application_number}}\n\nOn behalf of the entire team at Encore Mortgage, we want to say **congratulations** and thank you for trusting us with such an important milestone in your life.\n\n**Here\'s a summary of what just happened:**\n✅ Your loan documents were signed and notarized\n✅ The lender wired the funds to the title company\n✅ The title company recorded the transaction with the county\n✅ Ownership has been officially transferred — the property is YOURS\n\n**What to expect next:**\n\n📬 **Loan documents** — You\'ll receive your complete closing package by mail within 1–2 weeks. Keep these documents in a safe place — you\'ll need them for tax purposes.\n\n💳 **Your first mortgage payment** — Your first payment is typically due on the 1st of the month following 30 days after closing. Watch for your welcome letter from your loan servicer with payment instructions.\n\n🏠 **Loan servicer** — Your loan may be transferred to a loan servicer (which may differ from the lender). You\'ll receive a notification if this happens — it doesn\'t affect your loan terms.\n\n🧾 **Tax benefits** — Mortgage interest and property taxes may be deductible. Consult your tax advisor for details.\n\n📞 **We\'re still here** — If you ever need a refinance, have questions, or want to refer a friend or family member who needs a mortgage, we\'re always here for you.\n\nThank you again for choosing Encore Mortgage. We\'re so proud to have been part of your journey.\n\nWith warm congratulations,\n\n{{broker_name}}\nEncore Mortgage','[\"first_name\", \"application_number\", \"broker_name\"]',1,0,1,'2026-03-12 23:02:15','2026-03-12 23:02:15');
